import React, { useState } from 'react';
import axios from 'axios';
import { Button, Typography, Grid, Card, CardContent, Box, Alert, CircularProgress, IconButton, Chip, Avatar } from '@mui/material';
import { CameraAlt, Search, Face, CheckCircle, Error, Person } from '@mui/icons-material';

const RecognizeView = () => {
    const [image, setImage] = useState(null);
    const [results, setResults] = useState(null);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [severity, setSeverity] = useState('success');

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!image) return;

        setLoading(true);
        setMessage('');
        const formData = new FormData();
        formData.append('image', image);

        try {
            const response = await axios.post('/api/recognize', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            setResults(response.data);
            setMessage('Recognition completed successfully');
            setSeverity('success');
        } catch (error) {
            console.error('Recognition failed');
            setMessage('Recognition failed. Please try again.');
            setSeverity('error');
        }
        setLoading(false);
    };

    return (
        <Box sx={{ maxWidth: 1000, mx: 'auto' }}>
            <Typography variant="h5" gutterBottom sx={{ mb: 4, textAlign: 'center', fontWeight: 600 }}>
                <CameraAlt sx={{ mr: 1, verticalAlign: 'middle' }} />
                Face Recognition
            </Typography>

            <Grid container spacing={4}>
                <Grid item xs={12}>
                    <Card sx={{ p: 4 }}>
                        <CardContent>
                            <form onSubmit={handleSubmit}>
                                <Grid container spacing={3}>
                                    <Grid item xs={12}>
                                        <Box sx={{
                                            border: '2px dashed rgba(0, 188, 212, 0.5)',
                                            borderRadius: '16px',
                                            p: 4,
                                            textAlign: 'center',
                                            background: 'linear-gradient(145deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0.01))',
                                            transition: 'all 0.3s ease',
                                            '&:hover': {
                                                borderColor: '#00bcd4',
                                                background: 'linear-gradient(145deg, rgba(0, 188, 212, 0.05), rgba(0, 188, 212, 0.02))',
                                            }
                                        }}>
                                            <input
                                                accept="image/*"
                                                style={{ display: 'none' }}
                                                id="image-recognize"
                                                type="file"
                                                onChange={(e) => setImage(e.target.files?.[0] || null)}
                                            />
                                            <label htmlFor="image-recognize">
                                                <IconButton component="span" sx={{ fontSize: '3rem', color: '#00bcd4' }}>
                                                    <CameraAlt />
                                                </IconButton>
                                            </label>
                                            <Typography variant="h6" sx={{ mt: 2, color: 'text.secondary' }}>
                                                Upload Image for Recognition
                                            </Typography>
                                            <Typography variant="body2" sx={{ color: 'text.secondary' }}>
                                                Select a clear photo containing faces to recognize
                                            </Typography>
                                            {image && (
                                                <Typography variant="body2" sx={{ mt: 1, color: '#00bcd4' }}>
                                                    {image.name} selected
                                                </Typography>
                                            )}
                                        </Box>
                                    </Grid>

                                    <Grid item xs={12}>
                                        <Button
                                            type="submit"
                                            variant="contained"
                                            fullWidth
                                            disabled={loading || !image}
                                            sx={{
                                                py: 2,
                                                fontSize: '1.1rem',
                                                fontWeight: 600,
                                                borderRadius: '16px',
                                                background: 'linear-gradient(45deg, #00bcd4 30%, #ff4081 90%)',
                                                boxShadow: '0 8px 32px rgba(0, 188, 212, 0.4)',
                                                '&:hover': {
                                                    background: 'linear-gradient(45deg, #00bcd4 50%, #ff4081 100%)',
                                                    boxShadow: '0 12px 40px rgba(0, 188, 212, 0.6)',
                                                    transform: 'translateY(-2px)',
                                                },
                                                '&:disabled': {
                                                    background: 'rgba(255, 255, 255, 0.1)',
                                                    color: 'rgba(255, 255, 255, 0.3)',
                                                }
                                            }}
                                            startIcon={loading ? <CircularProgress size={20} /> : <Search />}
                                        >
                                            {loading ? 'Recognizing...' : 'Recognize Faces'}
                                        </Button>
                                    </Grid>
                                </Grid>
                            </form>
                        </CardContent>
                    </Card>
                </Grid>

                {message && (
                    <Grid item xs={12}>
                        <Alert
                            severity={severity}
                            sx={{
                                borderRadius: '16px',
                                fontSize: '1rem',
                                '& .MuiAlert-icon': {
                                    fontSize: '1.5rem',
                                }
                            }}
                            icon={severity === 'success' ? <CheckCircle /> : <Error />}
                        >
                            {message}
                        </Alert>
                    </Grid>
                )}

                {results && results.faces && results.faces.length > 0 && (
                    <Grid item xs={12}>
                        <Card sx={{ p: 4 }}>
                            <CardContent>
                                <Typography variant="h6" gutterBottom sx={{ mb: 3, fontWeight: 600 }}>
                                    <Face sx={{ mr: 1, verticalAlign: 'middle' }} />
                                    Recognition Results
                                </Typography>

                                <Grid container spacing={3}>
                                    {results.faces.map((face, idx) => (
                                        <Grid item xs={12} sm={6} md={4} key={idx}>
                                            <Card sx={{
                                                p: 3,
                                                background: 'linear-gradient(145deg, rgba(0, 188, 212, 0.1), rgba(255, 64, 129, 0.05))',
                                                border: '1px solid rgba(0, 188, 212, 0.3)',
                                                borderRadius: '16px',
                                                textAlign: 'center',
                                                transition: 'all 0.3s ease',
                                                '&:hover': {
                                                    transform: 'translateY(-4px)',
                                                    boxShadow: '0 8px 24px rgba(0, 188, 212, 0.3)',
                                                }
                                            }}>
                                                <Avatar sx={{
                                                    width: 60,
                                                    height: 60,
                                                    mx: 'auto',
                                                    mb: 2,
                                                    bgcolor: face.matches.length > 0 ? '#00bcd4' : '#ff4081'
                                                }}>
                                                    <Person />
                                                </Avatar>
                                                <Typography variant="h6" sx={{ mb: 1, fontWeight: 600 }}>
                                                    Face {idx + 1}
                                                </Typography>
                                                {face.matches.length > 0 ? (
                                                    <Box>
                                                        <Chip
                                                            label={face.matches[0].name}
                                                            color="primary"
                                                            sx={{
                                                                fontSize: '1rem',
                                                                fontWeight: 600,
                                                                px: 2,
                                                                py: 1,
                                                                borderRadius: '12px',
                                                            }}
                                                        />
                                                        <Typography variant="body2" sx={{ mt: 1, color: 'text.secondary' }}>
                                                            Confidence: {(face.matches[0].confidence * 100).toFixed(1)}%
                                                        </Typography>
                                                    </Box>
                                                ) : (
                                                    <Chip
                                                        label="Unknown"
                                                        color="secondary"
                                                        variant="outlined"
                                                        sx={{
                                                            fontSize: '1rem',
                                                            fontWeight: 600,
                                                            px: 2,
                                                            py: 1,
                                                            borderRadius: '12px',
                                                        }}
                                                    />
                                                )}
                                            </Card>
                                        </Grid>
                                    ))}
                                </Grid>
                            </CardContent>
                        </Card>
                    </Grid>
                )}
            </Grid>
        </Box>
    );
};

export default RecognizeView;
